1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	export function processScenario(input: any): unknown {
10	  const items = input.steps[0].items;
11	  if (items.length === 0) {
12	    return { results: [{ premium: PROCESSING_FEE }] };
13	  }
14	  const basePremium = BASE_PREMIUM_BY_TYPE[items[0].type];
15	  const premium = basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
16	  return { results: [{ premium }] };
17	}
